import type { I18nString } from '@/core/types';
import type { StoryFigureReliability } from '@/types';

export type StoryLibraryRowKind = 'arc' | 'normandyFigure';

export type StoryCategory =
  | 'Origins'
  | 'Conquest'
  | 'Expansion'
  | 'Exploration'
  | 'New France'
  | 'People'
  | 'Legacy';

export const STORY_CATEGORY_ORDER: StoryCategory[] = [
  'Origins',
  'Conquest',
  'Expansion',
  'Exploration',
  'New France',
  'People',
  'Legacy',
];

export type StoryTone = 'epic' | 'dark' | 'exploratory' | 'foundational' | 'personal';

export interface StoryLibraryMeta {
  arcId: string | null;
  category: StoryCategory;
  /** When set, the row also matches these category filters (primary `category` stays for badges and “All” sections). */
  alsoInCategories?: StoryCategory[];
  /** Synthetic arc rows from `NORMANDY_STORY_FIGURES` use `rowKind: 'normandyFigure'` and a prefixed `arcId`. */
  rowKind?: StoryLibraryRowKind;
  normandyFigureId?: string;
  normandyFigureReliability?: StoryFigureReliability;
  /** Long-form article under `/norman-readings/[slug]` when present. */
  normanReadingSlug?: string;
  /** `normanAtlanticStory` step id for legacy map chronicle handoff. */
  legacyAtlanticStoryStepId?: string;
  displayTitle?: I18nString;
  blurb: I18nString;
  hook?: I18nString;
  featured?: boolean;
  isNew?: boolean;
  thumb?: string;
  estimatedMinutes?: number;
  tone?: StoryTone;
  sortOrder?: number;
  recommendedEraId?: string;
  synopsisExtended?: I18nString;
  posterCredit?: I18nString;
}

/** Categories used for library filter chips (primary + secondary), deduped. */
export function libraryCategoryMembership(meta: StoryLibraryMeta): StoryCategory[] {
  const out: StoryCategory[] = [meta.category];
  const seen = new Set<StoryCategory>([meta.category]);
  for (const c of meta.alsoInCategories ?? []) {
    if (!seen.has(c)) {
      seen.add(c);
      out.push(c);
    }
  }
  return out;
}

export function storyLibraryMetaSharesCategory(a: StoryLibraryMeta, b: StoryLibraryMeta): boolean {
  const sa = new Set(libraryCategoryMembership(a));
  return libraryCategoryMembership(b).some((c) => sa.has(c));
}

