    sortOrder: 79,
    isNew: true,
    thumb: '/story/william-conqueror/tower-of-london.jpg',
    recommendedEraId: 'norman-expansion',
    displayTitle: { en: 'The March of Wales — Castles on the Frontier', fr: 'La Marche du Pays de Galles — Châteaux sur la Frontière', es: 'La Marca de Gales — Castillos en la Frontera', it: 'La Marca del Galles — Castelli sulla Frontiera', de: 'Der Marsch von Wales – Burgen an der Grenze', nb: 'The March of Wales - Castles on the Frontier', sv: 'The March of Wales - Castles on the Frontier', da: 'The March of Wales - Castles on the Frontier' },
    hook: { en: 'Two centuries of castle-building, intermarriage, and war on the Anglo-Welsh border.', fr: 'Deux siècles de construction de châteaux, de mariages mixtes et de guerre sur la frontière anglo-galloise.', de: 'Zwei Jahrhunderte Burgbau, Mischehen und Kriege an der anglo-walisischen Grenze.', nb: 'To århundrer med slottsbygging, inngifte og krig på den anglo-walisiske grensen.', sv: 'Två århundraden av slottsbyggande, blandäktenskap och krig vid den anglo-walesiska gränsen.', da: 'To århundreder med slotsbygning, blandet ægteskab og krig på den anglo-walisiske grænse.' },
    blurb: { en: 'Follow the Norman advance into Wales from Chepstow and Cardiff through Rhuddlan and Pembroke, and the Welsh counter-offensive under Owain Gwynedd.', fr: 'Suivez l\'avancée normande au Pays de Galles de Chepstow et Cardiff à Rhuddlan et Pembroke, et la contre-offensive galloise sous Owain Gwynedd.', de: 'Verfolgen Sie den Vormarsch der Normannen nach Wales von Chepstow und Cardiff nach Rhuddlan und Pembroke sowie die walisische Gegenoffensive unter Owain Gwynedd.', nb: 'Følg den normanniske fremrykningen inn i Wales fra Chepstow og Cardiff gjennom Rhuddlan og Pembroke, og den walisiske motoffensiven under Owain Gwynedd.', sv: 'Följ den normandiska framryckningen in i Wales från Chepstow och Cardiff genom Rhuddlan och Pembroke, och den walesiska motoffensiven under Owain Gwynedd.', da: 'Følg den normanniske fremrykning ind i Wales fra Chepstow og Cardiff gennem Rhuddlan og Pembroke, og den walisiske modoffensiv under Owain Gwynedd.' },
