    category: 'People',
    sortOrder: 81,
    isNew: true,
    thumb: '/story/william-conqueror/domesday-book.jpg',
    recommendedEraId: 'norman-expansion',
    displayTitle: { en: 'David I — The Norman King of Scots', fr: 'David Ier — Le Roi Normand d\'Écosse', es: 'David I — El Rey Normando de Escocia', it: 'Davide I — Il Re Normanno di Scozia', de: 'David I. – Der normannische König von Schottland', nb: 'David I - den normanniske kongen av skottene', sv: 'David I - den normandiska kungen av skotten', da: 'David I - den normanniske konge af skotterne' },
    hook: { en: 'A Scottish prince raised at the English court who remade his kingdom in the Anglo-Norman image.', fr: 'Un prince écossais élevé à la cour anglaise qui remodela son royaume à l\'image anglo-normande.', de: 'Ein am englischen Hof aufgewachsener schottischer Prinz, der sein Königreich nach anglonormannischem Vorbild umgestaltete.', nb: 'En skotsk prins oppvokst ved det engelske hoffet som gjenskapte riket sitt i det anglo-normanniske bildet.', sv: 'En skotsk prins uppvuxen vid det engelska hovet som gjorde om sitt kungarike till den anglo-normanska bilden.', da: 'En skotsk prins opvokset ved det engelske hof, som omskabte sit kongerige i det anglo-normanniske billede.' },
    blurb: { en: 'Follow David I from Henry I\'s court through the founding of abbeys and burghs, the Battle of the Standard, and the Davidian revolution that transformed medieval Scotland.', fr: 'Suivez David Ier de la cour d\'Henri Ier à la fondation d\'abbayes et de bourgs, la bataille de l\'Étendard et la révolution davidienne qui transforma l\'Écosse médiévale.', de: 'Folgen Sie David I. vom Hof ​​Heinrichs I. bis zur Gründung von Abteien und Marktstädten, der Schlacht an der Standarte und der davidischen Revolution, die das mittelalterliche Schottland veränderte.', nb: 'Følg David I fra Henry I\'s hoff gjennom grunnleggelsen av klostre og burghs, Battle of the Standard og den Davidianske revolusjonen som forvandlet middelalderens Skottland.', sv: 'Följ David I från Henry I:s hov genom grundandet av kloster och burgh, Battle of the Standard och den Davidska revolutionen som förvandlade det medeltida Skottland.', da: 'Følg David I fra Henry I\'s hof gennem grundlæggelsen af ​​klostre og burghs, Battle of the Standard og den Davidske revolution, der forvandlede middelalderens Skotland.' },
    estimatedMinutes: 4,
